def get_loggedin_user(request):   
     auth_header = request.headers['Authorization'] # Get the token from header of HTTP Request (Bearer Token)  
     
     if not auth_header:      
         return None       
         
     try: 
           token=auth_header.split(" ")[1]   
     except IndexError :            
            return None              # If no Bearer, then it's an unauthenticated user request  
     
     try:              
       payload = jwt.decode(token , 'YOUR_SECRET',algorithms=["HS256"])  # Decoding the token and getting back username   
       
       current_user =  next((x for x in users if x['username'] == payload['username']), None)  
     except:             
           return None           
     
     return current_user        
         
